import numpy as np

def predict(frame, action):
    g = np.array(frame, dtype=int).copy()
    H, W = g.shape
    BG = 5

    def find_active():
        # active cursor: a 0 cell whose 4 neighbors are an equal, non-bg color
        zr, zc = np.where(g == 0)
        for r, c in zip(zr.tolist(), zc.tolist()):
            if 0 < r < H-1 and 0 < c < W-1:
                u, d, l, rt = g[r-1,c], g[r+1,c], g[r,c-1], g[r,c+1]
                if u == d == l == rt and u != BG and u != 0:
                    return r, c, int(u)
        return None

    def find_solid():
        # inactive cursor: a cell equal to its 4 neighbors (the solid crossing)
        for r in range(1, H-1):
            for c in range(1, W-1):
                v = g[r, c]
                if v == BG or v == 0:
                    continue
                if g[r-1,c]==v and g[r+1,c]==v and g[r,c-1]==v and g[r,c+1]==v:
                    return r, c, int(v)
        return None

    def arm_cells(r, c, K):
        cells = [(r, c)]
        for dr, dc in ((-1,0),(1,0),(0,-1),(0,1)):
            rr, cc = r+dr, c+dc
            while 0 <= rr < H and 0 <= cc < W and g[rr, cc] == K:
                cells.append((rr, cc)); rr += dr; cc += dc
        return cells

    def advance_counter():
        cols = np.where(g[H-1] == 1)[0]
        if len(cols) == 0:
            g[H-1, W-1] = 1
        else:
            m = int(cols.min())
            if m - 1 >= 0:
                g[H-1, m-1] = 1

    deltas = {1:(-3,0), 2:(3,0), 3:(0,-3), 4:(0,3)}

    if action in deltas:
        act = find_active()
        if act is not None:
            r, c, K = act
            cells = arm_cells(r, c, K)
            dr, dc = deltas[action]
            for (rr, cc) in cells:
                g[rr, cc] = BG
            for (rr, cc) in cells:
                nr, nc = rr+dr, cc+dc
                if 0 <= nr < H and 0 <= nc < W:
                    g[nr, nc] = K
            if 0 <= r+dr < H and 0 <= c+dc < W:
                g[r+dr, c+dc] = 0
        advance_counter()
    elif action == 5:
        act = find_active()
        sol = find_solid()
        if act is not None:
            r, c, K = act
            g[r, c] = K
        if sol is not None:
            r, c, v = sol
            g[r, c] = 0
        advance_counter()
    else:
        advance_counter()

    return g
